import{_ as a,o as l,c as r,a2 as i}from"./chunks/framework.B72_uj9U.js";const b=JSON.parse('{"title":"政策模板","description":"","frontmatter":{},"headers":[],"relativePath":"zh/templates/policies.md","filePath":"zh/templates/policies.md"}'),e={name:"zh/templates/policies.md"};function d(o,t,h,n,s,u){return l(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="政策模板" tabindex="-1">政策模板 <a class="header-anchor" href="#政策模板" aria-label="Permalink to &quot;政策模板&quot;">​</a></h1><blockquote><p><strong>使用说明：</strong> 本节提供四项核心合规政策的模板文本。每项政策均包含完整的政策结构（目的、范围、政策声明、定义、职责、程序、违规处理、相关文件）。在正式颁布前，请根据企业实际情况修改占位符，并经法律顾问及高级管理层审核批准。</p><ul><li>政策版本应进行记录管理</li><li>员工须在培训后确认已阅读并理解政策</li><li>建议每两年进行政策审查和更新</li></ul></blockquote><hr><h2 id="政策一-反贿赂与反腐败政策" tabindex="-1">政策一：反贿赂与反腐败政策 <a class="header-anchor" href="#政策一-反贿赂与反腐败政策" aria-label="Permalink to &quot;政策一：反贿赂与反腐败政策&quot;">​</a></h2><p><strong>文件编号：</strong> ETHICS-POL-001 <strong>版本：</strong> [v1.0] <strong>发布日期：</strong> [YYYY-MM-DD] <strong>下次审阅日期：</strong> [YYYY+2-MM-DD] <strong>批准人：</strong> [CEO/总经理/董事会]</p><hr><h3 id="_1-目的" tabindex="-1">1. 目的 <a class="header-anchor" href="#_1-目的" aria-label="Permalink to &quot;1. 目的&quot;">​</a></h3><p>本政策旨在明确[公司全称]（下称&quot;本公司&quot;）对贿赂和腐败行为的零容忍立场，确保本公司及其代表在全球范围内的业务活动符合所有适用的反腐败法律法规，保护本公司的商业声誉和所有利益相关方的利益。</p><h3 id="_2-适用范围" tabindex="-1">2. 适用范围 <a class="header-anchor" href="#_2-适用范围" aria-label="Permalink to &quot;2. 适用范围&quot;">​</a></h3><p>本政策适用于：</p><ul><li>本公司全体员工（含正式员工、临时工、实习生）</li><li>本公司所有董事和管理人员</li><li>以本公司名义行事的第三方（代理商、顾问、分销商、合营合作方等）</li></ul><p>本政策在全球所有本公司开展业务的司法管辖区适用，包括但不限于中国大陆、香港、欧洲、北美洲及东南亚地区的业务。</p><h3 id="_3-适用法律框架" tabindex="-1">3. 适用法律框架 <a class="header-anchor" href="#_3-适用法律框架" aria-label="Permalink to &quot;3. 适用法律框架&quot;">​</a></h3><p>本政策旨在同时符合以下主要法律的要求：</p><table tabindex="0"><thead><tr><th>法律/法规</th><th>适用范围</th><th>主要义务</th></tr></thead><tbody><tr><td>中国《反不正当竞争法》（2019年修订）</td><td>中国境内及涉及中国业务的行为</td><td>禁止商业贿赂；最高处罚300万元罚款</td></tr><tr><td>英国《贿赂法案》（UKBA 2010）</td><td>有英国连接点的业务（含英国公司、英国居民、在英国运营）</td><td>对私营部门贿赂适用；企业须证明采取了充分的预防措施</td></tr><tr><td>美国《反海外腐败法》（FCPA）</td><td>涉及美国人、美国公司、美元结算或在美上市公司的行为</td><td>禁止向外国政府官员行贿；要求准确的会计记录</td></tr><tr><td>《联合国反腐败公约》（UNCAC）</td><td>签署国的通用义务</td><td>预防、刑事化、国际合作</td></tr></tbody></table><h3 id="_4-核心禁止行为" tabindex="-1">4. 核心禁止行为 <a class="header-anchor" href="#_4-核心禁止行为" aria-label="Permalink to &quot;4. 核心禁止行为&quot;">​</a></h3><p><strong>4.1 绝对禁止事项（零容忍，无任何例外）：</strong></p><ul><li>向任何人（政府官员或私营部门人员）提供、承诺、给予或接受金钱、礼品、服务或其他利益，以换取不正当商业利益</li><li>指示或允许第三方代表本公司进行上述行为</li><li>为掩盖贿赂行为而进行虚假的账目记录或文件处理</li><li>对内部举报进行打击报复</li></ul><p><strong>4.2 高风险行为（须严格审批，不得自行决定）：</strong></p><ul><li>在商业谈判进行期间向对方人员给予礼品或招待</li><li>向国有企业员工或可能具有政府背景的人员提供礼品或招待</li><li>向政府审批部门或监管机构工作人员提供礼品或招待</li><li>代理合同中约定高于行业惯例（&gt;15%）的佣金</li><li>向第三国账户付款（付款目的地与代理商注册地不一致）</li></ul><h3 id="_5-礼品与招待" tabindex="-1">5. 礼品与招待 <a class="header-anchor" href="#_5-礼品与招待" aria-label="Permalink to &quot;5. 礼品与招待&quot;">​</a></h3><p>5.1 所有礼品与招待须满足以下全部条件方为合规：</p><ul><li>符合本公司礼品招待政策规定的金额上限</li><li>有明确的合理商业目的</li><li>如实记录于礼品台账</li><li>不会影响或被合理认为会影响接受方的商业判断</li></ul><p>5.2 严格禁止的礼品形式：现金、礼品卡、购物券、贵金属及其等价物。</p><p>5.3 对政府官员的礼品与招待须适用更严格的标准（具体见礼品招待政策）。</p><h3 id="_6-第三方管理" tabindex="-1">6. 第三方管理 <a class="header-anchor" href="#_6-第三方管理" aria-label="Permalink to &quot;6. 第三方管理&quot;">​</a></h3><p><strong>本公司通过第三方进行的贿赂，其法律后果与本公司直接贿赂相同。</strong></p><p>6.1 所有新代理商、顾问和分销商须在签约前完成反腐败尽职调查（DD），包括：</p><ul><li>背景调查（含法院记录、媒体负面报道）</li><li>最终受益人（UBO）核查</li><li>参考客户访谈（如可行）</li></ul><p>6.2 所有第三方合同须包含以下条款：</p><ul><li>反腐败承诺和声明</li><li>本公司的审计权</li><li>违反反腐败条款可立即终止合同</li><li>所提供服务的具体描述（禁止仅以&quot;关系服务&quot;作为服务描述）</li></ul><p>6.3 对第三方的付款须有清晰的服务记录支撑，且须以银行转账方式支付至其注册地银行账户。</p><h3 id="_7-账簿与记录" tabindex="-1">7. 账簿与记录 <a class="header-anchor" href="#_7-账簿与记录" aria-label="Permalink to &quot;7. 账簿与记录&quot;">​</a></h3><p>本公司须按照所有适用法律（特别是FCPA账簿条款）的要求，准确记录所有交易：</p><ul><li>礼品与招待须在发生后[5个工作日]内记录于礼品台账</li><li>对代理商和顾问的付款须有详细的服务说明和发票</li><li>与高风险第三方的往来记录须保存至少[7年]</li></ul><h3 id="_8-举报与调查" tabindex="-1">8. 举报与调查 <a class="header-anchor" href="#_8-举报与调查" aria-label="Permalink to &quot;8. 举报与调查&quot;">​</a></h3><p>8.1 鼓励所有员工和业务合作方通过以下渠道举报可疑贿赂行为：</p><ul><li>内部举报热线：[电话号码]（24小时）</li><li>匿名邮箱：[邮箱地址]</li><li>直接向合规部门或法务部门报告</li></ul><p>8.2 所有举报将被认真对待。本公司绝对禁止对举报人进行打击报复；违反此规定的行为将受到最严肃处分。</p><p>8.3 所有可信的违规举报将由[合规部门/内部审计/外部律师]进行调查。</p><h3 id="_9-违规处理" tabindex="-1">9. 违规处理 <a class="header-anchor" href="#_9-违规处理" aria-label="Permalink to &quot;9. 违规处理&quot;">​</a></h3><ul><li>违反本政策的员工可能面临：书面警告、降级、停职或解除劳动合同</li><li>视情节轻重，可能向司法机关报告</li><li>管理人员因未能防止下属违规行为亦须承担相应责任</li></ul><h3 id="_10-培训与意识" tabindex="-1">10. 培训与意识 <a class="header-anchor" href="#_10-培训与意识" aria-label="Permalink to &quot;10. 培训与意识&quot;">​</a></h3><ul><li>所有员工须在入职时完成反腐败基础培训，并每[两年]复训一次</li><li>高风险岗位（采购、销售、对外关系、海外业务）须每年接受针对其岗位风险的专项培训</li><li>培训完成情况须记录存档</li></ul><h3 id="_11-相关文件" tabindex="-1">11. 相关文件 <a class="header-anchor" href="#_11-相关文件" aria-label="Permalink to &quot;11. 相关文件&quot;">​</a></h3><ul><li>礼品与招待政策（ETHICS-POL-002）</li><li>利益冲突政策（ETHICS-POL-003）</li><li>举报人保护政策（ETHICS-POL-004）</li><li>礼品台账表单（GH-FORM-001）</li><li>供应商行为准则</li></ul><hr><h2 id="政策二-礼品与招待政策" tabindex="-1">政策二：礼品与招待政策 <a class="header-anchor" href="#政策二-礼品与招待政策" aria-label="Permalink to &quot;政策二：礼品与招待政策&quot;">​</a></h2><p><strong>文件编号：</strong> ETHICS-POL-002 <strong>版本：</strong> [v1.0] <strong>发布日期：</strong> [YYYY-MM-DD] <strong>批准人：</strong> [CEO/总经理]</p><hr><h3 id="_1-目的-1" tabindex="-1">1. 目的 <a class="header-anchor" href="#_1-目的-1" aria-label="Permalink to &quot;1. 目的&quot;">​</a></h3><p>规范本公司员工在礼品给予和接受方面的行为，在维护商业关系的同时确保合规，防止礼品和招待演变为腐败行为。</p><h3 id="_2-适用范围-1" tabindex="-1">2. 适用范围 <a class="header-anchor" href="#_2-适用范围-1" aria-label="Permalink to &quot;2. 适用范围&quot;">​</a></h3><p>全体员工；对外代表本公司活动的第三方。</p><h3 id="_3-允许的礼品与招待标准" tabindex="-1">3. 允许的礼品与招待标准 <a class="header-anchor" href="#_3-允许的礼品与招待标准" aria-label="Permalink to &quot;3. 允许的礼品与招待标准&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类别</th><th>接受方为私营企业</th><th>接受方为国有企业员工</th><th>接受方为政府/监管机构人员</th></tr></thead><tbody><tr><td>单次礼品价值上限</td><td>≤ [500] 元人民币</td><td>≤ [200] 元人民币</td><td>≤ [象征性纪念品，约50元]</td></tr><tr><td>年度累计上限（同一人/同一公司）</td><td>≤ [1,500] 元人民币</td><td>≤ [600] 元人民币</td><td>≤ [100] 元人民币</td></tr><tr><td>商务餐饮招待（人均）</td><td>≤ [500] 元人民币</td><td>≤ [300] 元人民币</td><td>≤ [200] 元人民币，须3人以上参加</td></tr><tr><td>娱乐活动（人均）</td><td>≤ [500] 元人民币</td><td>≤ [300] 元人民币</td><td>原则上不适用</td></tr><tr><td>差旅/住宿安排</td><td>须事先获得合规部门批准</td><td>须事先获得合规部门批准</td><td>原则上禁止</td></tr></tbody></table><blockquote><p><strong>注意：</strong> 以上标准为本政策阈值，但<strong>任何礼品都须有明确的商业目的，且不得发生在商业谈判期间</strong>。即便金额低于上限，如目的是换取特定商业利益，仍属违规。</p></blockquote><h3 id="_4-绝对禁止" tabindex="-1">4. 绝对禁止 <a class="header-anchor" href="#_4-绝对禁止" aria-label="Permalink to &quot;4. 绝对禁止&quot;">​</a></h3><ul><li>现金、礼品卡、购物券、贵金属（无论金额）</li><li>在对方机构正在审批本公司申请（合同、许可证等）期间提供任何礼品或招待</li><li>通过第三方代为给予或代为接受礼品，以规避本政策的金额限制</li><li>基于个人喜好或非商业目的的礼品（如私人旅游安排）</li></ul><h3 id="_5-特殊场景处理" tabindex="-1">5. 特殊场景处理 <a class="header-anchor" href="#_5-特殊场景处理" aria-label="Permalink to &quot;5. 特殊场景处理&quot;">​</a></h3><p><strong>节日礼品（如中秋、春节）：</strong></p><ul><li>公司名义的节日礼品赠送须经部门主管审批，并在预算中专项列明</li><li>员工个人名义的节日礼品适用上述金额限制</li></ul><p><strong>接受礼品：</strong></p><ul><li>收到的礼品价值超过上限时，须立即报告并通过礼品台账处理（退回或捐赠给慈善机构）</li><li>合理原因无法退回的礼品，须捐赠并记录</li></ul><p><strong>差旅和会议：</strong></p><ul><li>由供应商/客户全额赞助的差旅和会议须提前经合规部门批准</li><li>家庭成员参与的赞助差旅原则上不允许</li></ul><h3 id="_6-记录要求" tabindex="-1">6. 记录要求 <a class="header-anchor" href="#_6-记录要求" aria-label="Permalink to &quot;6. 记录要求&quot;">​</a></h3><ul><li>价值超过[200元]的礼品给予或接受，均须填写《礼品与招待台账》（GH-FORM-001）并提交审批</li><li>台账记录保存不少于[5年]</li><li>合规部门每季度审查礼品台账，识别异常模式</li></ul><h3 id="_7-审批流程" tabindex="-1">7. 审批流程 <a class="header-anchor" href="#_7-审批流程" aria-label="Permalink to &quot;7. 审批流程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>审批人</th></tr></thead><tbody><tr><td>常规礼品招待（≤阈值，对象为私营企业）</td><td>直属上级审批即可</td></tr><tr><td>超过阈值（≤阈值2倍）</td><td>直属上级+合规部门</td></tr><tr><td>超过阈值2倍</td><td>直属上级+合规部门+法务VP</td></tr><tr><td>涉及政府官员/国有企业（任何金额）</td><td>直属上级+合规部门+CEO</td></tr></tbody></table><hr><h2 id="政策三-利益冲突政策" tabindex="-1">政策三：利益冲突政策 <a class="header-anchor" href="#政策三-利益冲突政策" aria-label="Permalink to &quot;政策三：利益冲突政策&quot;">​</a></h2><p><strong>文件编号：</strong> ETHICS-POL-003 <strong>版本：</strong> [v1.0] <strong>发布日期：</strong> [YYYY-MM-DD] <strong>批准人：</strong> [CEO/总经理]</p><hr><h3 id="_1-目的-2" tabindex="-1">1. 目的 <a class="header-anchor" href="#_1-目的-2" aria-label="Permalink to &quot;1. 目的&quot;">​</a></h3><p>识别和管理可能影响员工客观判断的利益冲突情形，确保本公司的商业决策基于客观、公正的标准，而非个人利益。</p><h3 id="_2-什么是利益冲突" tabindex="-1">2. 什么是利益冲突 <a class="header-anchor" href="#_2-什么是利益冲突" aria-label="Permalink to &quot;2. 什么是利益冲突&quot;">​</a></h3><p>当员工的个人利益（财务利益、个人关系、其他职业关系）可能实际上或表面上影响其代表本公司做出商业决策时，即存在利益冲突。</p><p><strong>常见利益冲突情形包括（但不限于）：</strong></p><ul><li>员工或其近亲属（配偶、父母、子女、兄弟姐妹）在供应商/客户/竞争对手处持有股权或担任高管/董事</li><li>员工在本公司外兼职或经营与本公司存在竞争或业务往来的企业</li><li>员工从现有或潜在供应商/客户处获得超出正常商务惯例的个人利益（礼品、旅游、借款等）</li><li>员工参与涉及其近亲属所在企业的采购或合同决策</li></ul><h3 id="_3-申报义务" tabindex="-1">3. 申报义务 <a class="header-anchor" href="#_3-申报义务" aria-label="Permalink to &quot;3. 申报义务&quot;">​</a></h3><p>以下人员须在以下时点进行利益冲突申报：</p><ul><li><strong>申报人范围：</strong> 参与供应商选择、合同审批、采购谈判、供应商绩效评估的所有员工；所有管理层人员</li><li><strong>申报时点：</strong> 入职时；每年[1月31日]前完成年度更新申报；当申报情形发生变化时立即补充申报（不超过30天）</li></ul><p>申报使用《利益冲突申报表》（COI-FORM-001）。</p><h3 id="_4-申报后的处理原则" tabindex="-1">4. 申报后的处理原则 <a class="header-anchor" href="#_4-申报后的处理原则" aria-label="Permalink to &quot;4. 申报后的处理原则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情形</th><th>处理方式</th></tr></thead><tbody><tr><td>评估为无实质性利益冲突</td><td>存档备查，申报人继续正常履职</td></tr><tr><td>存在潜在但可管理的利益冲突</td><td>申报人从相关具体事项中回避（Recusal）；由直属上级指定替代决策人</td></tr><tr><td>存在实质性、无法管理的利益冲突</td><td>要求申报人解除相关利益关联（如转让股权）或调整岗位</td></tr><tr><td>拒绝申报或故意隐瞒</td><td>视为严重违规，按违规处理程序处理</td></tr></tbody></table><h3 id="_5-独立核查" tabindex="-1">5. 独立核查 <a class="header-anchor" href="#_5-独立核查" aria-label="Permalink to &quot;5. 独立核查&quot;">​</a></h3><p>合规部门将独立定期（每年至少一次）对采购决策相关人员进行UBO（实际受益人）核查，通过天眼查、企查查等工具对员工名单与供应商股东进行交叉比对，不依赖单一的申报渠道。</p><h3 id="_6-兼职与外部职务" tabindex="-1">6. 兼职与外部职务 <a class="header-anchor" href="#_6-兼职与外部职务" aria-label="Permalink to &quot;6. 兼职与外部职务&quot;">​</a></h3><ul><li>员工在外部兼职、担任顾问或兼任董事须事先获得本公司书面批准</li><li>外部职务不得干扰员工的本职工作，且不得涉及本公司的机密信息</li></ul><h3 id="_7-离职管理" tabindex="-1">7. 离职管理 <a class="header-anchor" href="#_7-离职管理" aria-label="Permalink to &quot;7. 离职管理&quot;">​</a></h3><ul><li>在本公司从事采购或有供应商访问权限的员工离职时，须在离职面谈中确认无遗留的利益冲突问题</li><li>视岗位敏感程度，可能设定[6-24个月]的竞业限制期</li></ul><hr><h2 id="政策四-举报人保护政策" tabindex="-1">政策四：举报人保护政策 <a class="header-anchor" href="#政策四-举报人保护政策" aria-label="Permalink to &quot;政策四：举报人保护政策&quot;">​</a></h2><p><strong>文件编号：</strong> ETHICS-POL-004 <strong>版本：</strong> [v1.0] <strong>发布日期：</strong> [YYYY-MM-DD] <strong>批准人：</strong> [CEO/总经理]</p><hr><h3 id="_1-目的-3" tabindex="-1">1. 目的 <a class="header-anchor" href="#_1-目的-3" aria-label="Permalink to &quot;1. 目的&quot;">​</a></h3><p>为举报可疑违规行为的人员提供明确的保护承诺，鼓励诚信举报，确保本公司能够及时发现和纠正违规行为。</p><h3 id="_2-受保护的举报行为" tabindex="-1">2. 受保护的举报行为 <a class="header-anchor" href="#_2-受保护的举报行为" aria-label="Permalink to &quot;2. 受保护的举报行为&quot;">​</a></h3><p>以下类型的举报受本政策保护：</p><ul><li>违反本公司行为准则、政策或程序的行为</li><li>违反适用法律法规（如劳工法、环保法、反腐败法）的行为</li><li>财务违规、欺诈或会计舞弊</li><li>工作场所安全危害</li><li>歧视或骚扰行为</li><li>供应商违反供应商行为准则的行为</li></ul><p><strong>举报人须以善意（Good Faith）举报</strong>，即有合理理由相信所举报的事项可能属实，而非出于恶意或个人目的。故意举报虚假信息不受本政策保护。</p><h3 id="_3-举报渠道" tabindex="-1">3. 举报渠道 <a class="header-anchor" href="#_3-举报渠道" aria-label="Permalink to &quot;3. 举报渠道&quot;">​</a></h3><p>本公司提供以下多种举报渠道：</p><table tabindex="0"><thead><tr><th>渠道</th><th>联系方式</th><th>是否支持匿名</th><th>管理方</th></tr></thead><tbody><tr><td>内部举报热线</td><td>[电话号码]（24小时）</td><td>支持</td><td>合规部门</td></tr><tr><td>举报邮箱</td><td>[邮箱地址]</td><td>可选择匿名</td><td>合规部门</td></tr><tr><td>第三方举报平台</td><td>[平台名称/网址]</td><td>支持完全匿名</td><td>独立第三方运营</td></tr><tr><td>向上级/合规部门直接报告</td><td>当面或书面</td><td>不支持</td><td>合规部门</td></tr><tr><td>向审计委员会举报（涉及高管的案件）</td><td>[邮箱地址]</td><td>支持</td><td>审计委员会</td></tr></tbody></table><blockquote><p><strong>供应商举报通道：</strong> 本公司鼓励供应商员工通过上述渠道举报供应链中的违规行为。</p></blockquote><h3 id="_4-保护承诺" tabindex="-1">4. 保护承诺 <a class="header-anchor" href="#_4-保护承诺" aria-label="Permalink to &quot;4. 保护承诺&quot;">​</a></h3><p>本公司作出以下明确承诺：</p><p><strong>4.1 保密性：</strong> 举报人的身份信息在调查完成前严格保密。即便调查结论需要披露举报人信息（如需其出庭作证），本公司将提前告知举报人。知晓举报人身份的人员范围限于最小必要原则。</p><p><strong>4.2 禁止打击报复：</strong> 本公司严格禁止针对举报人的一切形式打击报复，包括但不限于：解雇、降级、减薪、调岗、孤立、骚扰、威胁或其他不利对待。对于打击报复者，本公司将采取纪律处分（可能包括解除劳动合同）。</p><p><strong>4.3 反馈机制：</strong> 举报人可要求了解举报处理进度（在保密要求允许的范围内）。所有举报须在[10个工作日]内确认收到，并在[45个工作日]内告知处理结论（或说明调查仍在进行及预计完成时间）。</p><p><strong>4.4 零容忍打击报复原则：</strong> 如举报人认为自己遭受了打击报复，可直接向合规部门、人力资源部门或审计委员会举报，此类案件将由高级管理层直接处理。</p><h3 id="_5-举报调查程序" tabindex="-1">5. 举报调查程序 <a class="header-anchor" href="#_5-举报调查程序" aria-label="Permalink to &quot;5. 举报调查程序&quot;">​</a></h3><p>5.1 <strong>接收：</strong> 所有举报在收到后[3个工作日]内进行初步评估，判断是否有可信的证据基础。</p><p>5.2 <strong>分级：</strong> 按严重程度分为一般合规问题（合规部门主导）、重大违规/可能涉及刑事（外部律师介入）、涉及高层人员（审计委员会主导）。</p><p>5.3 <strong>证据保全：</strong> 在开始调查前立即采取证据保全措施（限制相关账户访问、冻结相关文件删除权限）。</p><p>5.4 <strong>调查：</strong> 遵循&quot;由外围到核心&quot;的访谈顺序；保持书面记录；调查结论形成书面报告。</p><p>5.5 <strong>处置与反馈：</strong> 调查结论通知相关方；对违规行为采取纪律和/或法律行动；向举报人反馈处理结论（保密要求允许范围内）。</p><p>5.6 <strong>涉及高层人员：</strong> 凡涉及副总裁级别及以上人员的举报，调查工作须转由外部律师主导，并同时通知审计委员会，以保护律师-客户特权并确保调查独立性。</p><h3 id="_6-外部举报权利" tabindex="-1">6. 外部举报权利 <a class="header-anchor" href="#_6-外部举报权利" aria-label="Permalink to &quot;6. 外部举报权利&quot;">​</a></h3><p>本政策不限制员工依法向相关政府主管机构（如劳动局、市场监管局、税务局、公安机关等）举报违法行为的权利。本公司不会因员工向监管机构举报而对其进行打击报复。</p><h3 id="_7-政策传达" tabindex="-1">7. 政策传达 <a class="header-anchor" href="#_7-政策传达" aria-label="Permalink to &quot;7. 政策传达&quot;">​</a></h3><ul><li>本政策通过员工入职培训、公司内网、员工手册及年度合规培训向全体员工传达</li><li>举报渠道信息须张贴于工作场所显眼位置</li><li>本政策的供应商版本通过供应商门户系统和供应商行为准则向供应商传达</li></ul><hr><p><em>以上四项政策构成本公司商业道德合规体系的核心支柱。如需配套文件，请参阅<a href="./forms.html">操作表单</a>中的对应表单。</em></p>',125)])])}const c=a(e,[["render",d]]);export{b as __pageData,c as default};
